SELECT ?position ?time WHERE {
  wd:Q309095 p:P4274 ?statement .
  ?statement ps:P4274 ?position .
  ?statement pq:P585 ?time .
  FILTER(YEAR(?time) = 2021)
}

SELECT ?position WHERE {
  wd:Q309095 wdt:P5138 ?season .
  ?season rdfs:label ?label .
  FILTER(LANG(?label) = 'en' && CONTAINS(?label, '2021') && CONTAINS(?label, 'season')) .
  ?season wdt:P4274 ?position .
}

SELECT ?position WHERE {
  wd:Q309095 wdt:P5138 ?season .
  ?season rdfs:label ?label .
  FILTER(LANG(?label) = 'en' && regex(?label, '2021', 'i')) .
  ?season wdt:P4274 ?position .
}

